// ── Multi-Provider LLM Call ────────────────────────────────────────────
// Reads LLM_PROVIDER from env: claude | openai | gemini
// Falls back gracefully if provider is unavailable.

const provider = ($env.LLM_PROVIDER || 'claude').toLowerCase();
const prompt   = 'Analyze this CVE for enterprise impact. CVE: ' + $json.cve_id + '. CVSS: ' + $json.cvss_score + '. Description: ' + $json.description + '. Source: ' + $json.source + '.\n\nProvide in 3 sentences max: 1) What systems are affected? 2) What is the attack vector? 3) What is the immediate recommended action? Be specific and actionable.';
const maxTok   = 512;

let apiUrl, headers, body, modelKey;

if (provider === 'openai' || provider === 'gpt') {
  // ── OpenAI ──────────────────────────────────────────────────────────
  const model = $env.OPENAI_MODEL_FAST || $env.LLM_MODEL_PRIMARY || 'gpt-4o';
  apiUrl  = 'https://api.openai.com/v1/chat/completions';
  headers = {
    'Content-Type':  'application/json',
    'Authorization': 'Bearer ' + $env.OPENAI_API_KEY,
  };
  body = JSON.stringify({
    model,
    max_tokens: maxTok,
    messages: [{ role: 'user', content: prompt }],
  });
  modelKey = 'openai:' + model;

} else if (provider === 'gemini' || provider === 'google') {
  // ── Gemini ──────────────────────────────────────────────────────────
  const model = $env.GEMINI_MODEL_FAST || $env.LLM_MODEL_PRIMARY || 'gemini-1.5-pro';
  apiUrl  = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${$env.GOOGLE_API_KEY}`;
  headers = { 'Content-Type': 'application/json' };
  body = JSON.stringify({
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: { maxOutputTokens: maxTok },
  });
  modelKey = 'gemini:' + model;

} else {
  // ── Claude (default) ─────────────────────────────────────────────────
  const model = $env.LLM_MODEL_FAST || 'claude-sonnet-4-6';
  apiUrl  = 'https://api.anthropic.com/v1/messages';
  headers = {
    'Content-Type':      'application/json',
    'x-api-key':         $env.ANTHROPIC_API_KEY,
    'anthropic-version': '2023-06-01',
  };
  body = JSON.stringify({
    model,
    max_tokens: maxTok,
    messages: [{ role: 'user', content: prompt }],
  });
  modelKey = 'claude:' + model;
}

// Make the HTTP call
const resp = await $helpers.httpRequest({
  method:  'POST',
  url:     apiUrl,
  headers: headers,
  body:    body,
});

// ── Extract text from provider-specific response format ───────────────
let responseText = '';
if (provider === 'openai' || provider === 'gpt') {
  responseText = resp.choices?.[0]?.message?.content || '';
} else if (provider === 'gemini' || provider === 'google') {
  responseText = resp.candidates?.[0]?.content?.parts?.[0]?.text || '';
} else {
  responseText = resp.content?.[0]?.text || '';
}

return [{ json: { responseText, modelKey, provider } }];

const alert = $input.first().json;
const analysis = $('AI: Analyze CVE Impact (Multi-Provider)').item.json?.responseText || 'Analysis unavailable';
const isCISA = alert.source === 'CISA_KEV';
const urgency = isCISA ? '🚨 ACTIVELY EXPLOITED' : `⚠️ CVSS ${alert.cvss_score}`;
const dueDate = alert.due_date ? `Due: ${alert.due_date}` : '';
return [{ json: { ...alert, analysis, urgency, isCISA, dueDate } }];

